def route_intent(state: CustomerState) -> str:
    if 'refund' in state['messages'][-1]:
        return 'refund_path'
    if state['crm_data'].get('tier') == 'vip':
        return 'escalation'
    return 'standard_support'

def should_escalate(state: CustomerState) -> str:
    return 'human_review' if state['needs_escalation'] else 'generate_response'

# Build graph
workflow = StateGraph(CustomerState)
workflow.add_node('retrieve', retrieve_kb)
workflow.add_node('crm', crm_lookup)
workflow.add_node('generate_response', generate_response)

workflow.set_entry_point('retrieve')
workflow.add_conditional_edges('retrieve', route_intent, {
    'refund_path': 'crm',
    'escalation': 'human_review',
    'standard_support': ['retrieve', 'crm']  # Parallel
})
workflow.add_conditional_edges('crm', should_escalate, {
    'human_review': 'human_review',
    'generate_response': 'generate_response'
})
workflow.add_edge('generate_response', END)

checkpointer = MemorySaver()
app = workflow.compile(checkpointer=checkpointer)

def parallel_research(state: CustomerState):
    return {
        'retrieve': state,
        'crm': {**state, 'customer_id': state['customer_id']}
    }

# Add parallel execution to graph
workflow.add_conditional_edges(
    'retrieve',
    lambda s: 'parallel' if s['intent'] == 'order_status' else 'single',
    {
        'parallel': 'research',
        'single': 'crm'
    }
)
workflow.add_node('research', parallel_research)

# Merge results from parallel branches
@workflow.mapper('research')
def merge_research(state, config):
    kb_config = config.updated({"thread_ts": config.get('thread_ts')}, node='retrieve')
    crm_config = config.updated({"thread_ts": config.get('thread_ts')}, node='crm')

    kb_state = app.get_state(kb_config).values
    crm_state = app.get_state(crm_config).values

    return {
        **state,
        'kb_results': kb_state['kb_results'],
        'crm_data': crm_state['crm_data']
    }

