from vex import verify, GuardrailConfig

customer_guardrails = GuardrailConfig(
    risk_profile='high',
    verifications=[
        'response_accuracy',
        'pii_filtering',
        'tone_consistency',
        'policy_compliance',
        'escalation_triggers'
    ]
)

def safe_invoke(input_state, config):
    raw_result = app.invoke(input_state, config)

    verified = verify(
        raw_result,
        guardrails=customer_guardrails,
        context={'customer_tier': 'vip', 'domain': 'support'}
    )

    if verified.status == 'approved':
        return verified.output
    else:
        return {'messages': ['Escalating to human agent for review.']}

from vex import verify

def vex_guardrails(state: CustomerState) -> CustomerState:
    verification_result = verify(
        state,
        guardrails=[
            {
                'name': 'customer_support_suite',
                'verifications': ['response_accuracy', 'pii_filtering', 'tone_consistency']
            }
        ],
        context={'intent': state['intent'], 'customer_id': state['customer_id']}
    )

    if verification_result.status == 'blocked':
        state['needs_escalation'] = True
        state['messages'] += ('[VEX] Flagged for review: ' + verification_result.reason,)

    return state

# Insert Vex node after research merge
workflow.add_node('vex_guardrails', vex_guardrails)
workflow.add_edge('research', 'vex_guardrails')
workflow.add_conditional_edges('vex_guardrails', should_escalate, {
    'human_review': 'human_review',
    'generate_response': 'generate_response'
})

from vex import Monitor

cycle_monitor = Monitor(
    name='support_cycle_detector',
    max_cycles=5,
    max_iterations=15,
    alert_on_violation=True
)

class VexMonitoredGraph:
    def __init__(self, app):
        self.app = app
        self.monitor = cycle_monitor

    def invoke(self, input_state, config):
        self.monitor.start_session(config['configurable']['thread_id'])

        try:
            result = self.app.invoke(input_state, config)
            self.monitor.record_state(result)

            if self.monitor.check_limits():
                return result
            else:
                return {'messages': ['Max conversation length reached. Escalating.'],
                       'needs_escalation': True}
        finally:
            self.monitor.end_session()

monitored_app = VexMonitoredGraph(app)
